1	<script>
2		// Turn the probe until the meter agrees.
3		// probeAngle: primary slider value, degrees, 0..360, step 5.
4		// lengthC1: named auxiliary control, relative length of candidate c1, 0.5..2, step 0.1.
5		let probeAngle = $state(90);
6		let lengthC1 = $state(1);
7	
8		let diagramEl = $state(null);
9	
10		const CENTER = 150;
11		const R = 55;
12		const MAX_SCORE = 2;
13	
14		const baseCandidates = [
15			{ name: 'c1', angle: 20 },
16			{ name: 'c2', angle: 70 },
17			{ name: 'c3', angle: 110 },
18			{ name: 'c4', angle: 160 }
19		];
20	
21		function computeHead(tipX, tipY, dirX, dirY, shaftLen) {
22			const headLen = shaftLen * 0.18;
23			const halfW = shaftLen * 0.09;
24			const backX = tipX - dirX * headLen;
25			const backY = tipY - dirY * headLen;
26			const perpX = -dirY;
27			const perpY = dirX;
28			const lx = backX + perpX * halfW;
29			const ly = backY + perpY * halfW;
30			const rx = backX - perpX * halfW;
31			const ry = backY - perpY * halfW;
32			return { backX, backY, poly: `${tipX},${tipY} ${lx},${ly} ${rx},${ry}` };
33		}
34	
35		let candidateData = $derived.by(() => {
36			return baseCandidates.map((c) => {
37				const len = c.name === 'c1' ? lengthC1 : 1;
38				const rad = (c.angle * Math.PI) / 180;
39				const dirX = Math.cos(rad);
40				const dirY = -Math.sin(rad);
41				const shaft = R * len;
42				const tipX = CENTER + dirX * shaft;
43				const tipY = CENTER + dirY * shaft;
44				const head = computeHead(tipX, tipY, dirX, dirY, shaft);
45				const labelR = R * 2 + 20;
46				const labelX = CENTER + dirX * labelR;
47				const labelY = CENTER + dirY * labelR;
48				const diff = ((probeAngle - c.angle) * Math.PI) / 180;
49				const score = Math.cos(diff) * len;
50				return { ...c, len, tipX, tipY, ...head, labelX, labelY, score };
51			});
52		});
53	
54		let probeGeom = $derived.by(() => {
55			const rad = (probeAngle * Math.PI) / 180;
56			const dirX = Math.cos(rad);
57			const dirY = -Math.sin(rad);
58			const shaft = R;
59			const tipX = CENTER + dirX * shaft;
60			const tipY = CENTER + dirY * shaft;
61			const head = computeHead(tipX, tipY, dirX, dirY, shaft);
62			const perpX = -dirY;
63			const perpY = dirX;
64			const labelX = CENTER + dirX * (R + 18) + perpX * 12;
65			const labelY = CENTER + dirY * (R + 18) + perpY * 12;
66			return { tipX, tipY, ...head, labelX, labelY };
67		});
68	
69		let probeHandlePos = $derived.by(() => ({
70			x: (probeGeom.tipX / 300) * 100,
71			y: (probeGeom.tipY / 300) * 100
72		}));
73	
74		let c1HandlePos = $derived.by(() => {
75			const c1 = candidateData.find((c) => c.name === 'c1');
76			return { x: (c1.tipX / 300) * 100, y: (c1.tipY / 300) * 100 };
77		});
78	
79		let leaderName = $derived.by(() =>
80			candidateData.reduce((best, c) => (c.score > best.score ? c : best), candidateData[0]).name
81		);
82	
83		function updateProbeFromEvent(e) {
84			if (!diagramEl) return;
85			const rect = diagramEl.getBoundingClientRect();
86			const scale = 300 / rect.width;
87			const lx = (e.clientX - rect.left) * scale;
88			const ly = (e.clientY - rect.top) * scale;
89			const dx = lx - CENTER;
90			const dy = ly - CENTER;
91			let deg = (Math.atan2(-dy, dx) * 180) / Math.PI;
92			if (deg < 0) deg += 360;
93			if (deg > 360) deg = 360;
94			probeAngle = deg;
95		}
96	
97		function onProbePointerDown(e) {
98			e.currentTarget.setPointerCapture(e.pointerId);
99			updateProbeFromEvent(e);
100			const move = (ev) => updateProbeFromEvent(ev);
101			const up = () => {
102				window.removeEventListener('pointermove', move);
103				window.removeEventListener('pointerup', up);
104			};
105			window.addEventListener('pointermove', move);
106			window.addEventListener('pointerup', up);
107		}
108	
109		function onProbeKeydown(e) {
110			let handled = true;
111			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = Math.min(360, probeAngle + 5);
112			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = Math.max(0, probeAngle - 5);
113			else if (e.key === 'Home') probeAngle = 0;
114			else if (e.key === 'End') probeAngle = 360;
115			else handled = false;
116			if (handled) e.preventDefault();
117		}
118	
119		function updateLengthFromEvent(e) {
120			if (!diagramEl) return;
121			const rect = diagramEl.getBoundingClientRect();
122			const scale = 300 / rect.width;
123			const lx = (e.clientX - rect.left) * scale;
124			const ly = (e.clientY - rect.top) * scale;
125			const dx = lx - CENTER;
126			const dy = ly - CENTER;
127			const dist = Math.sqrt(dx * dx + dy * dy);
128			let len = dist / R;
129			len = Math.min(2, Math.max(0.5, len));
130			lengthC1 = Math.round(len * 10) / 10;
131		}
132	
133		function onLengthPointerDown(e) {
134			e.currentTarget.setPointerCapture(e.pointerId);
135			updateLengthFromEvent(e);
136			const move = (ev) => updateLengthFromEvent(ev);
137			const up = () => {
138				window.removeEventListener('pointermove', move);
139				window.removeEventListener('pointerup', up);
140			};
141			window.addEventListener('pointermove', move);
142			window.addEventListener('pointerup', up);
143		}
144	
145		function onLengthKeydown(e) {
146			let handled = true;
147			if (e.key === 'ArrowRight' || e.key === 'ArrowUp')
148				lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
149			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown')
150				lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
151			else if (e.key === 'Home') lengthC1 = 0.5;
152			else if (e.key === 'End') lengthC1 = 2;
153			else handled = false;
154			if (handled) e.preventDefault();
155		}
156	</script>
157	
158	<div class="wrap" data-interactive="dot-alignment">
159		<p class="instruction">Drag the probe to score each candidate. Drag c1's handle to change its length.</p>
160	
161		<div class="diagram-wrap" bind:this={diagramEl}>
162			<svg
163				viewBox="0 0 300 300"
164				class="diagram-svg"
165				role="img"
166				aria-label="Diagram: an amber probe arrow rotates among four periwinkle candidate arrows, c1 through c4"
167			>
168				{#each candidateData as c (c.name)}
169					<line
170						x1={CENTER}
171						y1={CENTER}
172						x2={c.backX}
173						y2={c.backY}
174						stroke="var(--data-observed)"
175						stroke-width="2.2"
176						stroke-linecap="round"
177					/>
178					<polygon points={c.poly} fill="var(--data-observed)" />
179					<text x={c.labelX} y={c.labelY} class="arrow-label" text-anchor="middle" dominant-baseline="middle">
180						{c.name}
181					</text>
182				{/each}
183	
184				<line
185					x1={CENTER}
186					y1={CENTER}
187					x2={probeGeom.backX}
188					y2={probeGeom.backY}
189					stroke="var(--data-heat)"
190					stroke-width="2.2"
191					stroke-linecap="round"
192					class="probe-line"
193				/>
194				<polygon points={probeGeom.poly} fill="var(--data-heat)" />
195				<text
196					x={probeGeom.labelX}
197					y={probeGeom.labelY}
198					class="arrow-label probe-label"
199					text-anchor="middle"
200					dominant-baseline="middle"
201				>
202					probe
203				</text>
204			</svg>
205	
206			<div
207				class="handle probe-handle"
208				style="left: {probeHandlePos.x}%; top: {probeHandlePos.y}%; --handle-color: var(--data-heat);"
209				role="slider"
210				tabindex="0"
211				aria-label="probe angle in degrees"
212				aria-valuemin="0"
213				aria-valuemax="360"
214				aria-valuenow={Math.round(probeAngle)}
215				onpointerdown={onProbePointerDown}
216				onkeydown={onProbeKeydown}
217			></div>
218	
219			<div
220				class="handle length-handle"
221				style="left: {c1HandlePos.x}%; top: {c1HandlePos.y}%; --handle-color: var(--data-observed);"
222				data-control="length-c1"
223				role="spinbutton"
224				tabindex="0"
225				aria-label="c1 length"
226				aria-valuemin="0.5"
227				aria-valuemax="2"
228				aria-valuenow={lengthC1.toFixed(1)}
229				onpointerdown={onLengthPointerDown}
230				onkeydown={onLengthKeydown}
231			></div>
232		</div>
233	
234		<div class="bars">
235			{#each candidateData as c (c.name)}
236				<div class="bar-col">
237					<div class="bar-track">
238						<div class="bar-zero"></div>
239						<div
240							class="bar-fill"
241							class:leading={c.name === leaderName}
242							style="height: {Math.min(Math.abs(c.score) / MAX_SCORE, 1) * 40}px; {c.score >= 0
243								? 'bottom: 50%;'
244								: 'top: 50%;'}"
245						></div>
246					</div>
247					<span class="readout" class:leading={c.name === leaderName}>{Math.round(c.score)}</span>
248					<span class="cand-label">{c.name}</span>
249				</div>
250			{/each}
251		</div>
252	</div>
253	
254	<style>
255		.wrap {
256			display: flex;
257			flex-direction: column;
258			align-items: center;
259			gap: 1rem;
260			width: 100%;
261			max-width: 520px;
262			margin: 0 auto;
263			padding: 1rem;
264			box-sizing: border-box;
265		}
266	
267		.instruction {
268			font-family: var(--font-body);
269			color: var(--color-text);
270			font-size: 0.9rem;
271			opacity: 0.85;
272			text-align: center;
273			margin: 0;
274		}
275	
276		.diagram-wrap {
277			position: relative;
278			width: 100%;
279			max-width: 420px;
280			aspect-ratio: 1 / 1;
281		}
282	
283		.diagram-svg {
284			width: 100%;
285			height: 100%;
286			display: block;
287		}
288	
289		.arrow-label {
290			font-family: var(--font-mono);
291			fill: var(--color-text);
292			font-size: 13px;
293			pointer-events: none;
294			user-select: none;
295		}
296	
297		.probe-label {
298			font-size: 13px;
299		}
300	
301		.handle {
302			position: absolute;
303			width: 44px;
304			height: 44px;
305			transform: translate(-50%, -50%);
306			display: flex;
307			align-items: center;
308			justify-content: center;
309			touch-action: none;
310			cursor: grab;
311			background: transparent;
312			border: none;
313			padding: 0;
314		}
315	
316		.handle::before {
317			content: '';
318			width: 14px;
319			height: 14px;
320			border-radius: 50%;
321			background: var(--handle-color);
322			box-shadow: 0 0 0 3px var(--color-bg);
323		}
324	
325		.handle:focus-visible::before {
326			box-shadow: 0 0 0 3px var(--color-bg), 0 0 0 5px var(--handle-color);
327		}
328	
329		.bars {
330			display: flex;
331			justify-content: center;
332			gap: 1.25rem;
333			width: 100%;
334			flex-wrap: wrap;
335		}
336	
337		.bar-col {
338			display: flex;
339			flex-direction: column;
340			align-items: center;
341			gap: 0.25rem;
342			min-width: 60px;
343		}
344	
345		.bar-track {
346			position: relative;
347			width: 26px;
348			height: 80px;
349		}
350	
351		.bar-zero {
352			position: absolute;
353			left: 0;
354			right: 0;
355			top: 50%;
356			height: 1px;
357			background: var(--color-text);
358			opacity: 0.3;
359		}
360	
361		.bar-fill {
362			position: absolute;
363			left: 0;
364			right: 0;
365			background: var(--data-params);
366			opacity: 0.55;
367			transition: height 150ms ease-out, top 150ms ease-out, bottom 150ms ease-out;
368		}
369	
370		.bar-fill.leading {
371			opacity: 1;
372		}
373	
374		.readout {
375			font-family: var(--font-mono);
376			color: var(--data-params);
377			font-size: 0.8rem;
378			opacity: 0.7;
379		}
380	
381		.readout.leading {
382			opacity: 1;
383			font-weight: 700;
384		}
385	
386		.cand-label {
387			font-family: var(--font-mono);
388			color: var(--color-text);
389			font-size: 0.75rem;
390			opacity: 0.75;
391		}
392	
393		@media (prefers-reduced-motion: reduce) {
394			.bar-fill {
395				transition: none;
396			}
397		}
398	</style>
